/// Retry HTTP request with exponential backoff.
async fn retry_request(
    client: &reqwest::Client,
    request: reqwest::RequestBuilder,
    max_retries: u32,
) -> anyhow::Result<reqwest::Response> {
    use anyhow::Context;
    use std::time::Duration;
    let mut last_error = None;
    for retry in 0..=max_retries {
        let req = request.try_clone().context("Failed to clone request for retry")?;
        match req.send().await {
            Ok(resp) if resp.status().is_success() => {
                return Ok(resp);
            }
            Ok(resp) if resp.status() == 429 => {
                let backoff = resp
                    .headers()
                    .get("retry-after")
                    .and_then(|v| v.to_str().ok())
                    .and_then(|s| s.parse::<u64>().ok())
                    .unwrap_or_else(|| 2_u64.pow(retry));
                tracing::warn!(
                    retry = retry, backoff_secs = backoff,
                    "Rate limited (429), backing off"
                );
                tokio::time::sleep(Duration::from_secs(backoff)).await;
                last_error = Some(
                    anyhow::anyhow!("Rate limited after {} retries", retry + 1),
                );
            }
            Ok(resp) if resp.status().is_server_error() => {
                let status = resp.status();
                let backoff = 2_u64.pow(retry);
                tracing::warn!(
                    retry = retry, status = % status, backoff_secs = backoff,
                    "Server error, retrying"
                );
                tokio::time::sleep(Duration::from_secs(backoff)).await;
                last_error = Some(anyhow::anyhow!("Server error: {}", status));
            }
            Ok(resp) => {
                let status = resp.status();
                let body = resp.text().await.unwrap_or_default();
                return Err(anyhow::anyhow!("HTTP error {}: {}", status, body));
            }
            Err(e) => {
                let backoff = 2_u64.pow(retry);
                tracing::warn!(
                    retry = retry, error = % e, backoff_secs = backoff,
                    "Network error, retrying"
                );
                tokio::time::sleep(Duration::from_secs(backoff)).await;
                last_error = Some(anyhow::anyhow!("Network error: {}", e));
            }
        }
    }
    Err(
        last_error
            .unwrap_or_else(|| {
                anyhow::anyhow!("Request failed after {} retries", max_retries)
            }),
    )
}
/// Extract nested data using a simple JSONPath-like notation.
fn extract_json_path(
    json: &serde_json::Value,
    path: &str,
) -> anyhow::Result<serde_json::Value> {
    let mut current = json.clone();
    for segment in path.trim_start_matches("$.").split('.') {
        if let Some(idx) = segment.find('[') {
            let key = &segment[..idx];
            let bracket_content = &segment[idx + 1..segment.len() - 1];
            if !key.is_empty() {
                current = current
                    .get(key)
                    .cloned()
                    .ok_or_else(|| anyhow::anyhow!("Path segment '{}' not found", key))?;
            }
            if bracket_content == "*"
            {} else if let Ok(index) = bracket_content.parse::<usize>() {
                current = current
                    .get(index)
                    .cloned()
                    .ok_or_else(|| {
                        anyhow::anyhow!("Array index {} out of bounds", index)
                    })?;
            }
        } else {
            current = current
                .get(segment)
                .cloned()
                .ok_or_else(|| anyhow::anyhow!("Path segment '{}' not found", segment))?;
        }
    }
    Ok(current)
}
